// ========================================
// STEP 1: Extract Clarification Data
// Naming convention: Match Notion field names
// ========================================

const clarification = $input.first().json;
const properties = clarification.properties || {};

// ========== DYNAMIC FIELD EXTRACTION ==========
// Group fields by type for smart detection
const fieldsByType = {
  title: [],
  relation: [],
  rich_text: [],
  select: [],
  date: []
};

for (const [fieldName, fieldData] of Object.entries(properties)) {
  const fieldType = fieldData.type;
  if (fieldsByType[fieldType]) {
    fieldsByType[fieldType].push({ name: fieldName, data: fieldData });
  }
}

// ========== EXTRACT BY FIELD TYPE + KEYWORD ==========
const getValue = (type, keywords) => {
  const fields = fieldsByType[type] || [];
  for (const f of fields) {
    const nameLC = f.name.toLowerCase();
    if (keywords.some(kw => nameLC.includes(kw.toLowerCase()))) {
      if (type === 'title') return { value: f.data.title?.[0]?.plain_text || '', fieldName: f.name };
      if (type === 'rich_text') return { value: f.data.rich_text?.[0]?.plain_text || '', fieldName: f.name };
      if (type === 'select') return { value: f.data.select?.name || '', fieldName: f.name };
      if (type === 'date') return { value: f.data.date?.start || '', fieldName: f.name };
    }
  }
  return { value: '', fieldName: null };
};

// Find relation field pointing to HR
let nguoiNhanChiDaoHR_Id = null;
let nguoiNhanChiDaoHR_FieldName = null;

for (const f of fieldsByType.relation) {
  if (f.data.relation?.length > 0) {
    const nameLC = f.name.toLowerCase();
    if (nameLC.includes('hr') || nameLC.includes('người') || nameLC.includes('nhận') || nameLC.includes('thực hiện')) {
      nguoiNhanChiDaoHR_Id = f.data.relation[0].id;
      nguoiNhanChiDaoHR_FieldName = f.name;
      break;
    }
    // Fallback: first relation with data
    if (!nguoiNhanChiDaoHR_Id) {
      nguoiNhanChiDaoHR_Id = f.data.relation[0].id;
      nguoiNhanChiDaoHR_FieldName = f.name;
    }
  }
}

// ========== EXTRACT VALUES (Matching Notion Field Names) ==========
// Title field
let tieuDe = '';
let tieuDe_FieldName = '';
for (const f of fieldsByType.title) {
  tieuDe = f.data.title?.[0]?.plain_text || '';
  tieuDe_FieldName = f.name;
  break;
}

const noiDungChiDao = getValue('rich_text', ['nội dung', 'chỉ đạo']);
const t2NhiemVu = getValue('rich_text', ['nhiệm vụ', 't2']);
const t3ChiTieu = getValue('rich_text', ['chỉ tiêu', 't3']);
const t4ThoiHan = getValue('date', ['thời hạn', 't4', 'deadline']);
const uuTien = getValue('select', ['ưu tiên', 'priority']);
const nguonGiaoViec = getValue('rich_text', ['nguồn']);

// Log field mapping for debugging
console.log('=== FIELD MAPPING ===');
console.log('Tiêu đề:', tieuDe_FieldName, '->', tieuDe);
console.log('Nội dung chỉ đạo:', noiDungChiDao.fieldName, '->', noiDungChiDao.value.substring(0, 50));
console.log('T2 - Nhiệm vụ:', t2NhiemVu.fieldName, '->', t2NhiemVu.value);
console.log('T3 - Chỉ tiêu:', t3ChiTieu.fieldName, '->', t3ChiTieu.value);
console.log('T4 - Thời hạn:', t4ThoiHan.fieldName, '->', t4ThoiHan.value);
console.log('Ưu tiên:', uuTien.fieldName, '->', uuTien.value);
console.log('Nguồn giao việc:', nguonGiaoViec.fieldName, '->', nguonGiaoViec.value);
console.log('Người nhận chỉ đạo (HR):', nguoiNhanChiDaoHR_FieldName, '->', nguoiNhanChiDaoHR_Id);

return {
  // Clarification info
  clarificationId: clarification.id,
  clarificationUrl: clarification.url || 'https://www.notion.so/' + clarification.id.replace(/-/g, ''),

  // Fields matching Notion names
  'Tiêu đề': tieuDe,
  'Nội dung chỉ đạo': noiDungChiDao.value,
  'T2 - Nhiệm vụ': t2NhiemVu.value,
  'T3 - Chỉ tiêu': t3ChiTieu.value,
  'T4 - Thời hạn': t4ThoiHan.value,
  'Ưu tiên': uuTien.value,
  'Nguồn giao việc': nguonGiaoViec.value || 'CEO',

  // HR relation
  'Người nhận chỉ đạo (HR)': nguoiNhanChiDaoHR_Id,

  // Field name mapping (for debugging)
  _fieldMapping: {
    tieuDe: tieuDe_FieldName,
    noiDungChiDao: noiDungChiDao.fieldName,
    t2NhiemVu: t2NhiemVu.fieldName,
    t3ChiTieu: t3ChiTieu.fieldName,
    t4ThoiHan: t4ThoiHan.fieldName,
    uuTien: uuTien.fieldName,
    nguonGiaoViec: nguonGiaoViec.fieldName,
    nguoiNhanChiDaoHR: nguoiNhanChiDaoHR_FieldName
  }
};

// ========================================
// STEP 2: Extract HR Info + Build Prefill URL
// ========================================

const clarData = $('Extract Clarification Data').first().json;
const hrPage = $('Get HR Page').first().json;
const hrProperties = hrPage.properties || {};

// ========== EXTRACT HR EMAIL & NAME ==========
let hrEmail = '';
let hrHoVaTen = '';

for (const [fieldName, fieldData] of Object.entries(hrProperties)) {
  const nameLC = fieldName.toLowerCase();
  const fieldType = fieldData.type;

  // Find Email field
  if (fieldType === 'email' && fieldData.email) {
    hrEmail = fieldData.email;
  }

  // Find Name field (title type)
  if (fieldType === 'title') {
    hrHoVaTen = fieldData.title?.[0]?.plain_text || '';
  }
  // Backup: rich_text with name keywords
  if (fieldType === 'rich_text' && (nameLC.includes('tên') || nameLC.includes('họ'))) {
    const text = fieldData.rich_text?.[0]?.plain_text || '';
    if (text && !hrHoVaTen) hrHoVaTen = text;
  }
}

// Fallback
if (!hrEmail) hrEmail = 'hoangkha@esuhai.com';
if (!hrHoVaTen) hrHoVaTen = 'Anh/Chị';

console.log('HR Email:', hrEmail);
console.log('HR Họ và Tên:', hrHoVaTen);

// ========== BUILD PREFILL URL ==========
const FORM_URL = 'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform?usp=pp_url';

// Entry IDs mapping
const ENTRY_IDS = {
  'clarificationId': 'entry.1684171280',
  'Tiêu đề': 'entry.1878008034',
  'Nội dung chỉ đạo': 'entry.1953342780',
  'T2 - Nhiệm vụ': 'entry.1839616630',
  'T3 - Chỉ tiêu': 'entry.649583359',
  'T4 - Thời hạn': 'entry.1319518938',
  'Ưu tiên': 'entry.1910876946',
  'Nguồn giao việc': 'entry.1661283634'
};

const params = {
  [ENTRY_IDS['clarificationId']]: clarData.clarificationId,
  [ENTRY_IDS['Tiêu đề']]: clarData['Tiêu đề'],
  [ENTRY_IDS['Nội dung chỉ đạo']]: clarData['Nội dung chỉ đạo'],
  [ENTRY_IDS['T2 - Nhiệm vụ']]: clarData['T2 - Nhiệm vụ'],
  [ENTRY_IDS['T3 - Chỉ tiêu']]: clarData['T3 - Chỉ tiêu'],
  [ENTRY_IDS['T4 - Thời hạn']]: clarData['T4 - Thời hạn'],
  [ENTRY_IDS['Ưu tiên']]: clarData['Ưu tiên'],
  [ENTRY_IDS['Nguồn giao việc']]: clarData['Nguồn giao việc']
};

const queryString = Object.keys(params)
  .map(key => key + '=' + encodeURIComponent(params[key] || ''))
  .join('&');

const prefillUrl = FORM_URL + '&' + queryString;

// Check 4T completeness
const has4T = clarData['Tiêu đề'] && 
              clarData['T2 - Nhiệm vụ'] && 
              clarData['T3 - Chỉ tiêu'] && 
              clarData['T4 - Thời hạn'];

const statusMessage = has4T 
  ? '✅ Chỉ đạo đã có đủ 4T. Vui lòng XÁC NHẬN và CAM KẾT thực hiện.'
  : '⚠️ Chỉ đạo còn thiếu thông tin. Vui lòng BỔ SUNG các trường còn trống.';

return {
  ...clarData,

  // HR info
  hrEmail,
  'Họ và Tên': hrHoVaTen,

  // Form
  prefillUrl,
  has4T,
  statusMessage
};
